<?php
require 'includes/auth.php'; require_login(); include 'config/db.php'; include 'includes/layout.php'; include 'includes/status_helper.php';
$where=[]; $params=[]; $types='';
$from=$_GET['from'] ?? ''; $to=$_GET['to'] ?? ''; $door=$_GET['door_id'] ?? ''; $severity=$_GET['severity'] ?? ''; $result=$_GET['result'] ?? ''; $q=$_GET['q'] ?? '';
if($from){ $where[]='l.event_time >= ?'; $params[]=$from.' 00:00:00'; $types.='s'; }
if($to){ $where[]='l.event_time <= ?'; $params[]=$to.' 23:59:59'; $types.='s'; }
if($door){ $where[]='l.door_id = ?'; $params[]=(int)$door; $types.='i'; }
if($severity){ $where[]='l.severity = ?'; $params[]=$severity; $types.='s'; }
if($result){ $where[]='l.result = ?'; $params[]=$result; $types.='s'; }
if($q){ $where[]='(l.actor_name LIKE ? OR l.event_type LIKE ? OR l.reason LIKE ? OR l.device_id LIKE ?)'; $like='%'.$q.'%'; array_push($params,$like,$like,$like,$like); $types.='ssss'; }
$sql='SELECT l.*, d.door_name, d.location FROM event_logs l LEFT JOIN doors d ON d.id=l.door_id '.($where?' WHERE '.implode(' AND ',$where):'').' ORDER BY l.event_time DESC LIMIT 500';
$stmt=$conn->prepare($sql); if($params){ $stmt->bind_param($types, ...$params); } $stmt->execute(); $res=$stmt->get_result();
$summary=$conn->query('SELECT result, COUNT(*) c FROM event_logs GROUP BY result');
$doors=$conn->query('SELECT id, door_code, door_name FROM doors ORDER BY id');
header_html('Forensic Report'); ?>
<div class="no-print"><h2>Generate Forensic Report</h2><p class="small-muted">Filter incidents, then print or save as PDF using your browser.</p>
<form class="row g-2 mb-3"><div class="col-md-2"><label>From</label><input type="date" class="form-control" name="from" value="<?=h($from)?>"></div><div class="col-md-2"><label>To</label><input type="date" class="form-control" name="to" value="<?=h($to)?>"></div><div class="col-md-2"><label>Door</label><select class="form-select" name="door_id"><option value="">All doors</option><?php while($d=$doors->fetch_assoc()): ?><option value="<?=$d['id']?>" <?=$door==$d['id']?'selected':''?>><?=h($d['door_code'].' - '.$d['door_name'])?></option><?php endwhile; ?></select></div><div class="col-md-2"><label>Status</label><select class="form-select" name="result"><option value="">All</option><?php foreach(['GRANTED','DENIED','WARNING','INFO'] as $x): ?><option <?=$result==$x?'selected':''?>><?=$x?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Severity</label><select class="form-select" name="severity"><option value="">All</option><?php foreach(['LOW','MEDIUM','HIGH','CRITICAL'] as $x): ?><option <?=$severity==$x?'selected':''?>><?=$x?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Search</label><input class="form-control" name="q" value="<?=h($q)?>" placeholder="user/event/reason"></div><div class="col-md-12 mt-2"><button class="btn btn-primary">Generate Report</button> <button type="button" onclick="window.print()" class="btn btn-success">Print / Save PDF</button> <a href="report.php" class="btn btn-outline-secondary">Reset</a></div></form></div>
<div class="card p-4"><div class="report-header"><h3>IoT Forensic Incident Report</h3><p class="mb-1"><b>Generated by:</b> <?=h($_SESSION['full_name'] ?? $_SESSION['username'])?> (<?=h($_SESSION['role'])?>)</p><p class="mb-1"><b>Generated at:</b> <?=date('Y-m-d H:i:s')?></p><p class="mb-0"><b>Purpose:</b> Event reconstruction, access review, door activity, and log integrity evidence.</p></div>
<h5>Report Summary</h5><div class="row mb-3"><?php while($s=$summary->fetch_assoc()): ?><div class="col-md-2"><div class="border rounded p-2"><small><?=h($s['result'])?></small><h4><?=h($s['c'])?></h4></div></div><?php endwhile; ?></div>
<h5>Incident Evidence Table</h5><table class="table table-bordered table-sm"><tr><th>No</th><th>When</th><th>Device/Door</th><th>Who</th><th>What Happened</th><th>Status</th><th>Severity</th><th>Reason / How</th><th>Integrity</th></tr><?php $i=1; while($r=$res->fetch_assoc()): ?><tr class="<?=row_class($r['result'],$r['event_type'],$r['integrity_status'])?>"><td><?=$i++?></td><td><?=h($r['event_time'])?></td><td><?=h($r['device_id'].' / '.$r['door_name'].' / '.$r['location'])?></td><td><?=h($r['actor_name'].' ('.$r['actor_role'].')')?></td><td><?=h($r['event_type'])?><br><small><?=h($r['auth_method'])?></small></td><td><?=status_badge($r['result'],$r['event_type'],$r['integrity_status'])?></td><td><span class="badge badge-sev-<?=h($r['severity'])?>"><?=h($r['severity'])?></span></td><td><?=h($r['reason'])?><br><small>IP: <?=h($r['source_ip'])?></small></td><td><?=h($r['integrity_status'])?><br><small class="hash"><?=h($r['stored_hash'])?></small></td></tr><?php endwhile; ?></table>
<div class="print-only"><br><p><b>Investigator Signature:</b> ___________________________</p><p><b>Date:</b> ___________________________</p></div></div>
<?php footer_html(); ?>
